// =============================================
// GADO.MIN.JS - Pseudo 3D Game Engine
// Version 2.3 - Vanilla JS + Canvas + Perspective
// =============================================

const GADO = {
  version: "2.3",
  canvas: null,
  ctx: null,
  camera: { x: 0, y: 0, z: 380, rotX: 0.35, rotY: 0.45 },
  cube: { rotX: 0, rotY: 0 },
  keys: {},
  mouse: { down: false },
  particles: [],

  init(canvasId = 'game') {
    this.canvas = document.getElementById(canvasId);
    if (!this.canvas) {
      this.canvas = document.createElement('canvas');
      this.canvas.width = 900;
      this.canvas.height = 600;
      document.body.appendChild(this.canvas);
    }
    this.ctx = this.canvas.getContext('2d');
    this.setupControls();
    this.gameLoop();
    console.log('%c🚀 GADO Pseudo-3D Engine v' + this.version + ' Loaded Successfully!', 'color:#0ff;font-size:18px');
  },

  setupControls() {
    window.addEventListener('keydown', e => this.keys[e.key.toLowerCase()] = true);
    window.addEventListener('keyup', e => this.keys[e.key.toLowerCase()] = false);

    this.canvas.addEventListener('mousedown', () => this.mouse.down = true);
    this.canvas.addEventListener('mouseup', () => this.mouse.down = false);
    this.canvas.addEventListener('mousemove', (e) => {
      if (this.mouse.down) {
        this.camera.rotY += e.movementX * 0.005;
        this.camera.rotX += e.movementY * 0.005;
      }
    });
  },

  project(x, y, z) {
    const dist = 580 / (z + this.camera.z);
    return {
      x: this.canvas.width / 2 + (x - this.camera.x) * dist,
      y: this.canvas.height / 2 + (y - this.camera.y) * dist
    };
  },

  spawnExplosion(x = 450, y = 280) {
    for (let i = 0; i < 160; i++) {
      this.particles.push({
        x: x,
        y: y,
        vx: Math.random() * 18 - 9,
        vy: Math.random() * 18 - 13,
        life: 75 + Math.random() * 45,
        size: 4 + Math.random() * 9,
        color: `hsl(${Math.random() * 70}, 100%, 65%)`
      });
    }
  },

  update() {
    if (this.keys['a'] || this.keys['arrowleft']) this.camera.x -= 7;
    if (this.keys['d'] || this.keys['arrowright']) this.camera.x += 7;
    if (this.keys['w'] || this.keys['arrowup']) this.camera.z -= 9;
    if (this.keys['s'] || this.keys['arrowdown']) this.camera.z += 9;
    if (this.keys[' ']) {
      this.spawnExplosion();
      this.keys[' '] = false;
    }

    this.cube.rotX += 0.012;
    this.cube.rotY += 0.017;

    // Update particles
    this.particles = this.particles.filter(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.38;
      p.life--;
      p.size *= 0.975;
      return p.life > 0;
    });
  },

  drawCube() {
    const size = 85;
    let points = [];

    for (let x = -1; x <= 1; x += 2) {
      for (let y = -1; y <= 1; y += 2) {
        for (let z = -1; z <= 1; z += 2) {
          let px = x * size;
          let py = y * size;
          let pz = z * size;

          // Rotation X
          let rx = py * Math.cos(this.cube.rotX) - pz * Math.sin(this.cube.rotX);
          let rz = py * Math.sin(this.cube.rotX) + pz * Math.cos(this.cube.rotX);
          py = rx; pz = rz;

          // Rotation Y
          let ry = px * Math.cos(this.cube.rotY) - pz * Math.sin(this.cube.rotY);
          pz = px * Math.sin(this.cube.rotY) + pz * Math.cos(this.cube.rotY);
          px = ry;

          points.push(this.project(px, py, pz));
        }
      }
    }

    this.ctx.strokeStyle = '#00ffff';
    this.ctx.lineWidth = 5;
    const edges = [[0,1],[1,3],[3,2],[2,0],[4,5],[5,7],[7,6],[6,4],[0,4],[1,5],[2,6],[3,7]];

    edges.forEach(([a, b]) => {
      this.ctx.beginPath();
      this.ctx.moveTo(points[a].x, points[a].y);
      this.ctx.lineTo(points[b].x, points[b].y);
      this.ctx.stroke();
    });
  },

  render() {
    // Background
    this.ctx.fillStyle = '#0a001f';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    this.drawCube();

    // Particles
    this.particles.forEach(p => {
      this.ctx.globalAlpha = p.life / 100;
      this.ctx.fillStyle = p.color;
      this.ctx.fillRect(p.x, p.y, p.size, p.size);
    });
    this.ctx.globalAlpha = 1;

    // HUD
    this.ctx.fillStyle = '#00ff88';
    this.ctx.font = 'bold 28px Arial';
    this.ctx.fillText('GADO Pseudo-3D Engine', 35, 55);
    this.ctx.font = '18px Arial';
    this.ctx.fillText('موس بکش • Space انفجار • WASD حرکت', 35, 85);
  },

  gameLoop() {
    this.update();
    this.render();
    requestAnimationFrame(() => this.gameLoop());
  }
};

// Export for CDN
window.GADO = GADO;